using System;

class Program {
    static void Main(string[] args) {
        Console.WriteLine("Hello, World!");
        Console.WriteLine(42);
        Console.WriteLine($"1 + 1 = {1 + 1}");
    }
}

class Person {
    public string Name { get; set; }
    public int Age { get; private set; }

    public Person(string name, int age) {
        Name = name;
        Age = age;
    }

    public string Introduce() =>
        $"Hi, I'm {Name}, {Age} years old.";
}

var p = new Person("Alice", 28);
Console.WriteLine(p.Introduce());

using System.Linq;

var numbers = new[] { 1, 2, 3, 4, 5, 6 };

var evens = numbers.Where(n => n % 2 == 0);
var doubled = numbers.Select(n => n * 2);
var first = numbers.FirstOrDefault(n => n > 3);

Console.WriteLine(string.Join(", ", evens));   // 2, 4, 6
Console.WriteLine(string.Join(", ", doubled)); // 2,4,6,8,10,12
Console.WriteLine(first);                      // 4

using System.Net.Http;

async Task<string> FetchAsync(string url) {
    using var client = new HttpClient();
    return await client.GetStringAsync(url);
}

async Task Main() {
    var html = await FetchAsync("https://example.com");
    Console.WriteLine(html.Length + " chars");
}
